def map_serializer(self, serializer):
        # Assuming we have a valid serializer instance.
        required = []
        properties = {}

        for field in serializer.fields.values():
            if isinstance(field, serializers.HiddenField):
                continue

            if field.required and not serializer.partial:
                required.append(self.get_field_name(field))

            schema = self.map_field(field)
            if field.read_only:
                schema['readOnly'] = True
            if field.write_only:
                schema['writeOnly'] = True
            if field.allow_null:
                schema['nullable'] = True
            if field.default is not None and field.default != empty and not callable(field.default):
                schema['default'] = field.default
            if field.help_text:
                schema['description'] = str(field.help_text)
            self.map_field_validators(field, schema)

            properties[self.get_field_name(field)] = schema

        result = {
            'type': 'object',
            'properties': properties
        }
        if required:
            result['required'] = required

        return result

def get_serializer_class(self, *args, **kwargs):
        if self.request.method not in SAFE_METHODS:
            try:
                obj_ = self.get_object()
                if isinstance(obj_, VirtualServer):
                    from ralph.virtual.api import VirtualServerSaveSerializer

                    return VirtualServerSaveSerializer
                elif isinstance(obj_, DataCenterAsset):
                    from ralph.data_center.api.serializers import (
                        DataCenterAssetSaveSerializer,
                    )

                    return DataCenterAssetSaveSerializer
                elif isinstance(obj_, CloudHost):
                    from ralph.virtual.api import SaveCloudHostSerializer

                    return SaveCloudHostSerializer
                elif isinstance(obj_, Cluster):
                    from ralph.data_center.api.serializers import ClusterSerializer

                    return ClusterSerializer
                else:
                    raise NotFound()
            except (
                AssertionError
            ):  # for some reason when opening browsable api this raises
                pass
        return ralph.assets.api.serializers_dchosts.DCHostSerializer

def migrate_endpoints_view(request):
    # Only superusers are allowed to perform endpoint migration
    if not request.user.is_superuser:
        raise PermissionDenied
    view_name = "Migrate endpoints"
    # Attempt to run the endpoint migration management command and handle success or failure
    if request.method == "POST":
        try:
            call_command("migrate_endpoints_to_locations")
            messages.add_message(
                request,
                messages.SUCCESS,
                "Endpoint migration completed successfully.",
                extra_tags="alert-success",
            )
        except Exception as e:
            logger.exception("Error during endpoint migration")
            messages.add_message(
                request,
                messages.ERROR,
                f"Endpoint migration failed: {e}",
                extra_tags="alert-danger",
            )

    return render(
        request, "dojo/migrate_endpoints.html", {
            "name": view_name,
        })

def clean(self):
        info = self.basket.strategy.fetch_for_product(self.product)

        # Check that a price was found by the strategy
        if not info.price.exists:
            raise forms.ValidationError(
                _(
                    "This product cannot be added to the basket because a "
                    "price could not be determined for it."
                )
            )

        # Check currencies are sensible
        if self.basket.currency and info.price.currency != self.basket.currency:
            raise forms.ValidationError(
                _(
                    "This product cannot be added to the basket as its currency "
                    "isn't the same as other products in your basket"
                )
            )

        # Check user has permission to add the desired quantity to their
        # basket.
        current_qty = self.basket.product_quantity(self.product)
        desired_qty = current_qty + self.cleaned_data.get("quantity", 1)
        is_permitted, reason = info.availability.is_purchase_permitted(desired_qty)
        if not is_permitted:
            raise forms.ValidationError(reason)

        return self.cleaned_data

