def dispatch(self, request, *args, **kwargs):
        # Try to dispatch to the right method; if a method doesn't exist,
        # defer to the error handler. Also defer to the error handler if the
        # request method isn't on the approved list.
        method = request.method.lower()
        if method in self.http_method_names:
            handler = getattr(self, method, self.http_method_not_allowed)
        else:
            handler = self.http_method_not_allowed
        return handler(request, *args, **kwargs)

    def http_method_not_allowed(self, request, *args, **kwargs):
        response = HttpResponseNotAllowed(self._allowed_methods())
        log_response(
            "Method Not Allowed (%s): %s",
            request.method,
            request.path,
            response=response,
            request=request,
        )

        if self.view_is_async:

            async def func():
                return response

            return func()
        else:
            return response

def login_user(request):
    try:
        data = json.loads(request.body)
    except json.JSONDecodeError:
        return HttpResponseBadRequest()
    if 'username' not in data:
        return HttpResponseBadRequest(
            json.dumps({"username": "this field is required"})
        )
    if 'password' not in data:
        return HttpResponseBadRequest(
            json.dumps({"password": "this field is required"})
        )
    user = authenticate(
        request,
        username=data['username'],
        password=data['password']
    )
    if not user:
        return HttpResponseBadRequest(
            json.dumps({"password": "username and password doesn't match"})
        )
    login(request, user)
    data = UserSerializer(
        user,
        context={'request': request},
    ).data
    return HttpResponse(
        JSONRenderer().render(data),
        content_type="application/json"
    )

def validate(self, data):
        user = None
        product = None
        template = False

        if self.instance is not None:
            user = self.instance.user
            product = self.instance.product

        if "user" in data:
            user = data.get("user")
        if "product" in data:
            product = data.get("product")
        if "template" in data:
            template = data.get("template")

        if (
            template
            and Notifications.objects.filter(template=True).count() > 0
        ):
            msg = "Notification template already exists"
            raise ValidationError(msg)
        if (
            self.instance is None
            or user != self.instance.user
            or product != self.instance.product
        ):
            notifications = Notifications.objects.filter(
                user=user, product=product, template=template,
            ).count()
            if notifications > 0:
                msg = "Notification for user and product already exists"
                raise ValidationError(msg)
        return data

def get_prep_value(self, value):
        obj = super().get_prep_value(value)
        if obj is None:
            return None
        # When the input is not a geometry or raster, attempt to construct one
        # from the given string input.
        if isinstance(obj, GEOSGeometry):
            pass
        else:
            # Check if input is a candidate for conversion to raster or
            # geometry.
            is_candidate = isinstance(obj, (bytes, str)) or hasattr(
                obj, "__geo_interface__"
            )
            # Try to convert the input to raster.
            raster = self.get_raster_prep_value(obj, is_candidate)

            if raster:
                obj = raster
            elif is_candidate:
                try:
                    obj = GEOSGeometry(obj)
                except (GEOSException, GDALException):
                    raise ValueError(
                        "Couldn't create spatial object from lookup value '%s'." % obj
                    )
            else:
                raise ValueError(
                    "Cannot use object with type %s for a spatial lookup parameter."
                    % type(obj).__name__
                )

        # Assigning the SRID value.
        obj.srid = self.get_srid(obj)
        return obj

def __init__(self, *expressions, **extra):
        super().__init__(*expressions, **extra)

        # Ensure that value expressions are geometric.
        for pos in self.geom_param_pos:
            expr = self.source_expressions[pos]
            if not isinstance(expr, Value):
                continue
            try:
                output_field = expr.output_field
            except FieldError:
                output_field = None
            geom = expr.value
            if (
                not isinstance(geom, GEOSGeometry)
                or output_field
                and not isinstance(output_field, GeometryField)
            ):
                raise TypeError(
                    "%s function requires a geometric argument in position %d."
                    % (self.name, pos + 1)
                )
            if not geom.srid and not output_field:
                raise ValueError("SRID is required for all geometries.")
            if not output_field:
                self.source_expressions[pos] = Value(
                    geom, output_field=GeometryField(srid=geom.srid)
                )

def render(self, context):
        from django.urls import NoReverseMatch, reverse

        args = [arg.resolve(context) for arg in self.args]
        kwargs = {k: v.resolve(context) for k, v in self.kwargs.items()}
        view_name = self.view_name.resolve(context)
        try:
            current_app = context.request.current_app
        except AttributeError:
            try:
                current_app = context.request.resolver_match.namespace
            except AttributeError:
                current_app = None
        # Try to look up the URL. If it fails, raise NoReverseMatch unless the
        # {% url ... as var %} construct is used, in which case return nothing.
        url = ""
        try:
            url = reverse(view_name, args=args, kwargs=kwargs, current_app=current_app)
        except NoReverseMatch:
            if self.asvar is None:
                raise

        if self.asvar:
            context[self.asvar] = url
            return ""
        else:
            if context.autoescape:
                url = conditional_escape(url)
            return url

def handle(self, *args, **options):
        options_schema = options.get("schema")

        if options_schema and isinstance(options_schema, str):
            module_str, schema_name = options_schema.rsplit(".", 1)
            mod = importlib.import_module(module_str)
            schema = getattr(mod, schema_name)

        elif options_schema:
            schema = options_schema

        else:
            schema = graphene_settings.SCHEMA

        out = options.get("out") or graphene_settings.SCHEMA_OUTPUT

        if not schema:
            raise CommandError(
                "Specify schema on GRAPHENE.SCHEMA setting or by using --schema"
            )

        indent = options.get("indent")
        watch = options.get("watch")
        if watch:
            autoreload.run_with_reloader(
                functools.partial(self.get_schema, schema, out, indent)
            )
        else:
            self.get_schema(schema, out, indent)

def update(self, instance, validated_data):
        if instance.notification.mandatory:
            raise serializers.ValidationError(
                "Attempting to set [%s] to %s. Mandatory notifications can't "
                'be modified'
                % (instance.notification.short, validated_data.get('enabled'))
            )

        enabled = validated_data['enabled']

        request = self.context['request']
        current_user = request.user

        remote_by_id = {ntfn.id: ntfn for ntfn in notifications.REMOTE_NOTIFICATIONS}

        if instance.notification_id in remote_by_id:
            notification = remote_by_id[instance.notification_id]
            if not enabled:
                unsubscribe_newsletter(current_user, notification.basket_newsletter_id)
            elif enabled:
                subscribe_newsletter(
                    current_user, notification.basket_newsletter_id, request=request
                )
        elif 'enabled' in validated_data:
            # Only save if non-mandatory and 'enabled' is set.
            # Ignore other fields.
            instance.enabled = validated_data['enabled']
            # Not .update because some of the instances are new.
            instance.save()
        return instance

def clean(self):
        if any(self.errors):
            return

        apps = list(
            filter(
                None,
                [
                    f.cleaned_data
                    for f in self.forms
                    if not f.cleaned_data.get('DELETE', False)
                ],
            )
        )

        if not apps:
            # At this point, we're raising a global error and re-displaying the
            # applications that were present before. We don't want to keep the
            # hidden delete fields in the data attribute, cause that's used to
            # populate initial data for all forms, and would therefore make
            # those delete fields active again.
            self.data = {
                k: v for k, v in self.data.items() if not k.endswith('-DELETE')
            }
            for form in self.forms:
                form.data = self.data
            raise forms.ValidationError(
                gettext('Need at least one compatible application.')
            )

def save(self, *args, **kwargs):
        # Store the given length (if any) in meters for use in database ordering
        if self.length and self.length_unit:
            self._abs_length = to_meters(self.length, self.length_unit)
        else:
            self._abs_length = None

        # Store the parent Device for the A and B terminations (if applicable) to enable filtering
        if hasattr(self.termination_a, "device"):
            self._termination_a_device = self.termination_a.device
        if (
            not self._termination_a_device
            and hasattr(self.termination_a, "module")
            and self.termination_a.module.device
        ):
            self._termination_a_device = self.termination_a.module.device
        if hasattr(self.termination_b, "device"):
            self._termination_b_device = self.termination_b.device
        if (
            not self._termination_b_device
            and hasattr(self.termination_b, "module")
            and self.termination_b.module.device
        ):
            self._termination_b_device = self.termination_b.module.device

        super().save(*args, **kwargs)

        # Update the private pk used in __str__ in case this is a new object (i.e. just got its pk)
        self._pk = self.pk

def _authenticate(
        self, request: HttpRequest | None, **credentials
    ) -> AbstractBaseUser | None:
        username: str | None = credentials.get("username")
        password: str = credentials.get("password") or ""
        if username:
            if LoginMethod.EMAIL in app_settings.LOGIN_METHODS:
                # Username/email ambiguity: even though allauth will pass along
                # `email` explicitly, other apps may not respect this. For example,
                # when using django-tastypie basic authentication, the login is
                # always passed as `username`.  So let's play nice with other apps
                # and use username as fallback.
                user = self._authenticate_by_email(username, password)
                if user:
                    return user
            user = self._authenticate_by_username(username, password)
            if user:
                return user

        email = credentials.get("email")
        if email:
            user = self._authenticate_by_email(email, password)
            if user:
                return user

        phone = credentials.get("phone")
        if phone:
            user = self._authenticate_by_phone(phone, password)
            if user:
                return user
        return None

def perform_mutation(cls, _root, info: ResolveInfo, /, **data):
        error = False
        try:
            user = models.User.objects.get(email=data["email"])
        except ObjectDoesNotExist:
            # If user doesn't exists in the database we create fake user for calculation
            # purpose, as we don't want to indicate non existence of user in the system.
            error = True
            user = models.User()

        valid_token = token_generator.check_token(user, data["token"])
        if not valid_token or error:
            raise ValidationError(
                {
                    "token": ValidationError(
                        INVALID_TOKEN, code=AccountErrorCode.INVALID.value
                    )
                }
            )

        user.is_active = True
        user.is_confirmed = True
        user.save(update_fields=["is_active", "is_confirmed", "updated_at"])

        match_orders_with_new_user(user)
        assign_user_gift_cards(user)

        cls.post_save_action(info, user)

        return ConfirmAccount(user=user)

def should_auto_approve(self, registration):
        if registration.is_public:
            return 'already public'

        if registration.is_registration_approved:
            return 'already approved'

        if registration.archiving:
            return 'still archiving'

        archive_job = registration.archive_job
        if archive_job and hasattr(archive_job, 'status'):
            if archive_job.status not in ['SUCCESS', None]:
                return f'archive status: {archive_job.status}'

        approval = registration.registration_approval
        if not approval:
            return 'no approval object'

        if approval.is_approved:
            return 'approval already approved'

        if approval.is_rejected:
            return 'approval was rejected'

        time_since_initiation = timezone.now() - approval.initiation_date
        if time_since_initiation < settings.REGISTRATION_APPROVAL_TIME:
            remaining = settings.REGISTRATION_APPROVAL_TIME - time_since_initiation
            return f'not ready yet ({remaining} remaining)'

        if registration.is_stuck_registration:
            return 'registration still stuck'

        return 'ready'

def get_new_connection(self, conn_params):
        conn = super().get_new_connection(conn_params)
        # Enabling extension loading on the SQLite connection.
        try:
            conn.enable_load_extension(True)
        except AttributeError:
            raise ImproperlyConfigured(
                "SpatiaLite requires SQLite to be configured to allow "
                "extension loading."
            )
        # Load the SpatiaLite library extension on the connection.
        for path in self.lib_spatialite_paths:
            try:
                conn.load_extension(path)
            except Exception:
                if getattr(settings, "SPATIALITE_LIBRARY_PATH", None):
                    raise ImproperlyConfigured(
                        "Unable to load the SpatiaLite library extension "
                        "as specified in your SPATIALITE_LIBRARY_PATH setting."
                    )
                continue
            else:
                break
        else:
            raise ImproperlyConfigured(
                "Unable to load the SpatiaLite library extension. "
                "Library names tried: %s" % ", ".join(self.lib_spatialite_paths)
            )
        return conn

def bounce_mail(message, reason):
    recipient_header = (
        None
        if not isinstance(message, dict)
        else message.get('From', message.get('ReplyTo'))
    )
    if not recipient_header:
        log.warning(
            'Tried to bounce incoming activity mail but no From or '
            'ReplyTo header present.'
        )
        return
    recipient = recipient_header.get('EmailAddress')
    try:
        recipient = sanitize_address(
            recipient_header.get('EmailAddress'), settings.DEFAULT_CHARSET
        )
    except ValueError:
        log.warning('Tried to bounce incoming activity mail but recipient is invalid')
        return

    body = loader.get_template('activity/emails/bounce.txt').render(
        {'reason': reason, 'SITE_URL': settings.SITE_URL}
    )
    send_mail(
        'Re: %s' % message.get('Subject', 'your email to us'),
        body,
        recipient_list=[recipient],
        use_deny_list=False,
    )

def setup_changed_version_ids_field(self, field, data):
        if not self.instance.id:
            field.choices = [
                (
                    block.guid,
                    [
                        (version.id, version.version)
                        for version in block.addon_versions
                        if self.should_version_be_available_for_action(version)
                    ],
                )
                for block in self.blocks
            ]

            self.changed_version_ids_choices = [
                v_id for _guid, opts in field.choices for (v_id, _text) in opts
            ]
            if not data and not self.initial.get('changed_version_ids'):
                # preselect all the options
                self.initial['changed_version_ids'] = self.changed_version_ids_choices
        else:
            field.choices = list(
                (v_id, v_id) for v_id in self.instance.changed_version_ids
            )
            self.changed_version_ids_choices = self.instance.changed_version_ids
        field.widget.choices = self.changed_version_ids_choices
        field.widget.blocks = self.blocks
        field.widget.action = self.action

def emit(self, record):
        if current_task is None:
            return

        # Skip recording the log entry if it has been marked as such
        if getattr(record, "skip_db_logging", False):
            return

        from nautobot.extras.models.jobs import JobResult

        try:
            self.format(record)

            try:
                job_result = JobResult.objects.get(id=record.task_id)
            except (ValidationError, JobResult.DoesNotExist):
                # Both of these cases are very rare
                # ValidationError - because the task_id might not a valid UUID
                # JobResult.DoesNotExist - because we might not have a JobResult with that ID
                return

            job_result.log(
                message=record.message,
                level_choice=record.levelname.lower(),
                obj=getattr(record, "object", None),
                grouping=getattr(record, "grouping", record.funcName),
            )
        except Exception:
            self.handleError(record)
